import { createTheme } from "@mui/material/styles";


const appTheme = createTheme({
    typography: {
        h1: {
          fontFamily: 'Avenir',
          fontSize: '24px',
          fontWeight: 900,
        },
        h2: {
          fontFamily: 'Avenir',
          fontSize: '24px',
          fontWeight: 400,
        },
        
        
      },
      palette: {
        primary: {
            main: '#D4415B',
            dark: '#79053D',
            light: '#E07A8D',
            background: '#DEBAC1',
            contrastText: '#FFFFFF'
        },
        secondary: {
            main: '#C13DAC',
            dark: '#862576',
            light: '#EA8DDB',
            background: '#E8B9E0'
        }
      },
      components: {
        MuiCssBaseline: {
          styleOverrides: `
          @font-face {
            font-family: 'Avenir';
            src: url(fonts/AvenirLTStd-Black.otf) format('otf'); 
            weight: 900;
            font-style: normal;
          }
          
          @font-face {
            font-family: 'Avenir';
            src: url(fonts/AvenirLTStd-Heavy.otf) format('otf'); 
            weight: 700;
            font-style: normal;
          }
          
          @font-face {
            font-family: 'Avenir';
            src: url(fonts/AvenirLTStd-Roman.otf) format('otf'); 
            weight: 400;
            font-style: normal;
          }

          @font-face {
            font-family: 'Avenir';
            src: url(fonts/AvenirLTStd-Light.otf) format('otf'); 
            weight: 300;
            font-style: normal;
          }
          `,
        },
      }
});

export default appTheme;
